#include <vector>
#include <string>
#include <regex>
#include <algorithm>
#include <map>

using namespace std;

vector<string> solve(vector<string> code, vector<string> businessLine, vector<bool> isActive) {
    vector<string> allowedBusinessLines = {"electronics", "grocery", "pharmacy", "restaurant"};
    map<string, int> businessOrderMap;
    for (size_t i = 0; i < allowedBusinessLines.size(); ++i) {
        businessOrderMap[allowedBusinessLines[i]] = i;
    }

    vector<pair<string, string>> valid;
    for (size_t i = 0; i < code.size(); ++i) {
        const string& c = code[i];
        const string& bl = businessLine[i];
        bool active = isActive[i];

        if (!c.empty() && regex_match(c, regex("^[a-zA-Z0-9_]+$")) && businessOrderMap.find(bl) != businessOrderMap.end() && active) {
            valid.push_back({c, bl});
        }
    }

    sort(valid.begin(), valid.end(), [&](const pair<string, string>& a, const pair<string, string>& b) {
        int idxA = businessOrderMap[a.second];
        int idxB = businessOrderMap[b.second];
        if (idxA != idxB) return idxA < idxB;
        return a.first < b.first;
    });

    vector<string> result;
    for (const auto& p : valid) {
        result.push_back(p.first);
    }

    return result;
}
